var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"진짜 짜증나게 구네……!","JPN":"まったくイライラさせてくれる……！","ENG":"Ugh...! They're so annoying...!","TWN":"真會找麻煩……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이까짓 장난감들은 빠르게 돌파해 버리면 그만이야!","JPN":"こんなオモチャは素早く突破しちゃえば問題ない！","ENG":"We just have to make it through these toys!","TWN":"等我搞定這些玩具他們就完蛋了！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이, 이게 뭐야? 발에 다 들러붙었어!","JPN":"な、何だこれ？　足にくっついた！","ENG":"H-huh?! My feet are stuck to something!","TWN":"這…這是什麼？整個都黏到腳上！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"끈끈이 덫이다! 실제로는 처음 봐!","JPN":"とりもちだ！　実際に見るのは初めて！","ENG":"It's a sticky trap! I've never seen one in real life before!","TWN":"黏黏的是陷阱！第一次看到！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"누가 나 좀 잡아……","JPN":"誰か、ちょっと引っ張って……","ENG":"Someone grab me pleas─","TWN":"誰來拉我一把……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK_02"},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"저기 공 날아온다!","JPN":"ボールが飛んでくるよ！","ENG":"Watch out for those balls!","TWN":"有球飛過來！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"으악!","JPN":"わあっ！","ENG":"Ack!","TWN":"呃啊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BALL"},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"씨이, 이건 또 뭔데!! 사람 놀리냐?!","JPN":"くそ、こりゃ何なんだよ！！　おちょくってんのか！？","ENG":"Grr...! What the heck was that?! Is this some sick joke?!","TWN":"該死，這又是怎樣！！耍人嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"크으. 역시 헤이븐 형님! 어설픈 잔재주는 통하지 않아!","JPN":"くぅ。さすがヘイブン兄貴！　生半可な小細工は通じないね！","ENG":"Khhh. Mr. Haven strikes again! He sees right through your clumsy tricks!","TWN":"唔，不愧是天堂大哥！小聰明是行不通的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"감탄만 하지 말고 나 좀 여기서 떼어내 줘!","JPN":"感心してないで早く私をここから剝がしてよ！","ENG":"Stop admiring his work and help me out of this mess!","TWN":"現在不是讚嘆的時候，趕快把我弄出去！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"알았어, 알았다고.","JPN":"わかった、わかったって。","ENG":"Okay, fine.","TWN":"好好好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜 경비가 없나 했더니만, 이런 함정이 숨겨져 있을 줄이야.","JPN":"警備がいないと思ったら、こんな罠が隠されてたなんてね。","ENG":"Now we know why security's so low here. Who knew there would be so many booby traps?","TWN":"才在想說怎麼沒有人看著，原來是有陷阱！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"대체 우리 형님은 어디까지 내다 보신 거지?","JPN":"いったい兄貴はどこまで見通してたんだろう？","ENG":"I mean, how many steps ahead could he have planned for?","TWN":"我們大哥到底會做到什麼程度呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그냥 방탈출 게임 같은 데 썼던 어트랙션 같은데… 대충 치워 두고 잊어 버린 거 아닐까?","JPN":"単に脱出ゲームとかで使った備品みたいだけど……適当に片付けて忘れてたんじゃないかな？","ENG":"I think they're just attractions used in the escape room games... Maybe he forgot to clean up after putting them here?","TWN":"感覺像是玩密室逃脫時用過的道具…是不是沒收拾乾淨，忘在這裡啦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"또 또 답답한 소리하네, 얘는.","JPN":"またまた、わかってないな。こいつ。","ENG":"Ugh, you really don't know him, do you?","TWN":"你又來，又在說這些有的沒的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"겉모습만 따라하면 안 된다니까, 겉모습만. 형님에 대해 마음 속 깊은 곳까지 공명하라고.","JPN":"外見だけマネしてもダメなんだって。兄貴と心の奥深いところまで共鳴し合わないと。","ENG":"Like I said, it's not enough just imitating his style. You need to learn how he thinks and acts.","TWN":"就跟你說不能只模仿外表，要連內心深處也對大哥有認同感好嗎！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아니, 들을수록 헤이븐에 대한 네 기준선이 너무 높은 것 같아…….","JPN":"聞けば聞くほどヘイブンに対する君のハードルは高すぎる気が……","ENG":"The more I hear you talk about him, the more I believe you have unrealistic expectations of him...","TWN":"不是，我怎麼越聽越覺得，是你把天堂想得太美好……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그나저나 이제 어쩐다. 시작부터 난관이네.","JPN":"それにしてもどうしよう。初めから難関に突きあたっちゃったじゃん。","ENG":"Anyway, what now? We've hit a brick wall from the start.","TWN":"不過現在該怎麼辦？有點出師不利欸。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"너무 단순한 기계들이라 해킹도 통하지 않아.","JPN":"単純過ぎる機械でハッキングも通じないよ。","ENG":"These machines are too simple to be hacked.","TWN":"它們就是普通的機器，就算駭進去也沒用。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"맞아. 계속 말을 걸어도 대답을 안 해 줘.","JPN":"うん。ずっと話しかけてるけど答えてくれない。","ENG":"Yeah. They don't even answer when I talk to them.","TWN":"對啊，跟它們說話也都不回應。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"큰일이네. 도로시가 실패할 정도면 우리 중에는 아무도 통과 못할 텐데…….","JPN":"困ったね。ドロシーが失敗するくらいだから、私たちには無理だろうし……","ENG":"This is bad... If Dorothy can't make it, then none of us can...","TWN":"糟糕，要是連桃樂絲都失敗的話，那我們當中應該沒人可以通過吧……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"저기, 그런데 있잖아.","JPN":"あの、ところでさ。","ENG":"Um... I have a question, though.","TWN":"不過，我想問一下，"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤이븐 랜드는 불시착시켜서 어디에 쓰게?","JPN":"ヘイブンランドを不時着させてどうするつもりなの？","ENG":"What are you planning to do after crash-landing Havenland?","TWN":"讓天堂樂園迫降是想做什麼？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"여기에서 일하고 있는 아이들을 구할 거야.","JPN":"ここで働いてる子たちを助けるんだよ。","ENG":"We're going to save the children who work here.","TWN":"要救出在這裡工作的孩子。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아이들?","JPN":"子ども？","ENG":"The children?","TWN":"孩子？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"응. 여기서 일하는, 위저드 출신 친구들.","JPN":"そう。ここで働いてる、ウィザード出身の友達。","ENG":"Yup. Our \\"Wizard\\" friends, who work here.","TWN":"沒錯，在這裡工作，來自巫師的孩子。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"왜? 위저드 출신 아이들은 여기서 잘 지내고 있는 거 아니야?","JPN":"なんで？　ウィザード出身の子どもたちはここで幸せに暮らしてると思ってたけど？","ENG":"But why? Don't they live great lives here?","TWN":"為什麼？來自巫師的孩子不是在這裡過得很好嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"잘 지내긴 뭘 잘 지내. 아무것도 모르고 이용당하는 마당에.","JPN":"幸せに暮らすって冗談でしょ？　何も知らないまま利用されてるのに。","ENG":"As if. They're being exploited and they don't even know it.","TWN":"有什麼好？他們什麼都不知道，是被人利用的。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"이용당해? 대체 무슨 얘기야?","JPN":"利用されてる？　どういうこと？","ENG":"exploited? What are you talking about?","TWN":"被人利用？這是什麼意思？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"설명하자면 복잡해. 하지만 나쁜 의도는 없어.","JPN":"説明するには複雑すぎるよ。でも悪気はない。","ENG":"It's complicated. But we don't mean to harm them.","TWN":"說來話長，不過我們沒惡意。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"……알겠어.","JPN":"……わかった。","ENG":"...Okay.","TWN":"……好吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"실은 엔진실에 들어갈 방법이 있어. 그거면 엔진실이 아니라 함교에도 갈 수 있을 거야.","JPN":"実はエンジンルームに入る方法があるんだ。その方法ならエンジンルームじゃなくて艦橋にも行けるはずだよ。","ENG":"You know, there's a way to enter the engine room. It'll allow you to enter not just the engine room, but access the bridge as well.","TWN":"其實有方法可以進去引擎室，而且不只是引擎室，連艦橋都進得去。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐? 그게 뭔데?","JPN":"その方法ってのは何なんだよ？","ENG":"What? How do we do that?","TWN":"什麼？是什麼方法？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"바로……","JPN":"それは……","ENG":"We do that by...","TWN":"就是……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"이벤트에 참가해서 <color=#ffd34c>VIP 카드</color>를 모으는 거야!","JPN":"イベントに参加して<color=#ffd34c>VIPカード</color>を集めることさ！","ENG":"Joining the event and collecting <color=#ffd34c>VIP cards</color>!","TWN":"就是參加活動收集<color=#ffd34c>VIP卡</color>！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L1_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"윽. 설마 <color=#ffd34c>다음 헤이븐은 바로 당신입니다.</color> 하는 거?","JPN":"うっ。まさか<color=#ffd34c>次のヘイブンはあなたです。</color>のあれ？","ENG":"Eww... You don't mean that <color=#ffd34c>\\"The next Haven is you\\"</color> thing, right?","TWN":"呃，該不會是指<color=#ffd34c>下一個天堂就是你！</color>吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"맞아! 바로 그거!","JPN":"そう！　それ！","ENG":"Yeah! That's the one!","TWN":"沒錯！就是那個！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"헤이븐 랜드는 크게 4개의 구역으로 나뉘어져 있어.","JPN":"ヘイブンランドは大きく4つの区域に分けられてる。","ENG":"Havenland is divided into 4 big areas.","TWN":"天堂樂園可以分為4大區域。"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"먼저 온갖 놀이기구를 탈 수 있는 <color=#ffd34c>퍼스트 헤이븐 파크</color>!","JPN":"まず、あらゆるアトラクションを楽しめる<color=#ffd34c>ファーストヘイブンパーク</color>！","ENG":"First, there's the <color=#ffd34c>First Haven Park</color> where you can ride all kinds of amusement park rides!","TWN":"首先是可以搭乘各樣遊樂器材的<color=#ffd34c>第一天堂主題公園</color>!"},"stage":{"bg":"PARK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"다음은 <color=#ffd34c>드림 네버 랜드</color>. 초호화 수영장이 딸린 리조트야.","JPN":"次は<color=#ffd34c>ドリームネバーランド</color>。豪華なプールつきのリゾートなんだ。","ENG":"Then, there's <color=#ffd34c>Dream Neverland</color>. A resort with a luxurious pool!","TWN":"再來是<color=#ffd34c>夢幻樂園</color>，有著超豪華游泳池的度假村。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그 다음은 <color=#ffd34c>라스트 헤이븐</color>.","JPN":"その次は<color=#ffd34c>ラストヘイブン</color>。","ENG":"After that you have <color=#ffd34c>Last Haven</color>.","TWN":"接下來是<color=#ffd34c>最後的天堂</color>。"},"stage":{"bg":"CLUB1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"철저한 계산과 심리 싸움, 연기력까지 발휘해야 하는 보드 게임의 성지지.","JPN":"徹底的な計算と心理戦、演技力まで発揮しないといけないボードゲームの聖地だよ。","ENG":"The mecca of board games that require precise calculations, using psychological mind games, and acting!","TWN":"攻心為上的心理戰，甚至需要發揮演技的桌遊勝地。"},"stage":{"bg":"CLUB1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그리고 마지막은…… <color=#ffd34c>디 엔드 랜드</color>.","JPN":"そして最後は……<color=#ffd34c>ジ・エンドランド</color>。","ENG":"And last, but not least... <color=#ffd34c>The End Land</color>.","TWN":"最後是……<color=#ffd34c>終點站樂園</color>。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"바로…… 투기장이야.","JPN":"つまり……闘技場だ。","ENG":"The... Colosseum.","TWN":"就是……競技場。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤이븐 형님의 스테이지!","JPN":"ヘイブン兄貴のステージ！","ENG":"That's Mr. Haven's stage!","TWN":"是天堂大哥的關卡！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"도전자들의 피와 땀이 흐르고, 내리쬐는 태양 아래 전력을 다해 상대를 분쇄하는 곳이지!","JPN":"挑戦者の血と汗が流れ、照りつける太陽の下で全力をつくして相手を打ち砕く場所！","ENG":"Where challengers spill blood and sweat under the scorching sun to bash their opponents!","TWN":"那裡是挑戰者流血流汗，在大太陽底下盡全力粉碎對手的地方！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아니. 그냥 서로 규칙을 지키면서 실력을 겨루는 건전한 종합 격투기 스포츠인데.","JPN":"いや。ただお互いルールを守りながら実力を競う、健全な総合格闘技場なんだけど。","ENG":"No, it's a sound MMA sport in which competitors fight while adhering to a set of rules.","TWN":"不是，是雙方遵守規則，彼此較勁的綜合格鬥運動。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"상대를 가차없이 때려눕혀야 헤이븐 형님이지! 지금 형님을 모욕하는 거냐?!","JPN":"相手を容赦なく殴り倒してこそヘイブン兄貴じゃん！　今兄貴を侮辱してる！？","ENG":"But Mr. Haven mercilessly rips his opponents a new one! Wait, did you just insult him?!","TWN":"毫不留情地打趴對手才像天堂大哥的作風吧！你現在是在污辱大哥嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"모욕은 누가 하고 있는데?!","JPN":"侮辱してるのは君だろ！？","ENG":"Hey, who's insulting who right now, huh?!","TWN":"到底是誰在侮辱人？！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"잠깐! 친구끼리 싸우면 안 돼!","JPN":"ちょっと！　友達同士でケンカしちゃダメ！","ENG":"Stop it! No fighting among friends!","TWN":"好了！朋友之間不可以吵架！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"맞아. 다 큰 사람들이 애들 앞에서 뭐 하는 거야.","JPN":"そうだよ。大の大人が、子どもたちの前で何してるの？","ENG":"She's right. You're adults, so act like it.","TWN":"對啊，都這麼大的人了，在孩子面前像什麼樣？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"……미안.","JPN":"……ごめん。","ENG":"...Sorry.","TWN":"……抱歉。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……흥.","JPN":"……ふん。","ENG":"...Hmph.","TWN":"……哼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아무튼, 이렇게 4개 구역에는 헤이븐을 비롯한 간부들이 담당자로 있어.","JPN":"とにかく、この4つの区域はヘイブンと幹部たちが担当してる。","ENG":"Anyway, the 4 areas each have a consigliere in charge, including Haven.","TWN":"總之，這4個區域是由天堂帶領幹部負責。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그 사람들에게 도전해서 이기면 VIP 카드를 얻는 거야.","JPN":"その人たちに挑戦して勝てばVIPカードをもらえるんだ。","ENG":"And if you challenge them and win, you get a VIP card.","TWN":"向他們挑戰並獲勝就可以獲得VIP卡。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"카드 4장을 전부 모으면, 헤이븐 랜드의 주인이 될 수 있지!","JPN":"4枚のカードが全部揃うと、ヘイブンランドの主になれる！","ENG":"After collecting all 4, you can become the owner of Havenland!","TWN":"4張卡片全都收集到後，就可以成為天堂樂園的主人！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 이 커다란 배를 주는구나. 재밌겠다.","JPN":"おお、このおっきい船をくれるんだね。面白そう。","ENG":"Ooh...! They're giving away this huge ship? That sounds fun.","TWN":"哇喔，會給我這麼大的船嗎？感覺好好玩喔！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L33_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그치? 말만 들어도 진짜 재밌겠지?","JPN":"だろ？　聞くだけでもすごく面白そうだと思うよね？","ENG":"I know, right? Doesn't it sound like so much fun?","TWN":"對吧？光聽就覺得很好玩吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잘 몰라서 그러는데, 헤이븐 랜드를 상품으로 걸어도 되는 건가?","JPN":"よくわかんないけど、ヘイブンランドを景品にしちゃってもいいの？","ENG":"I'm just asking, but can they just put Havenland as the winning prize?","TWN":"我不太懂，意思是把天堂樂園當作獎品嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"아, 아마 더 좋은 사람에게 맡기고 싶어서 아닐까?","JPN":"た、たぶんもっといい人にヘイブンランドを任せたかったんじゃないかな？","ENG":"M-maybe they want to find someone who can run this place better, you know?","TWN":"喔，可能是想交給更適合的人管理吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"흐음. 확실히 나쁘진 않은 방식이네. 이 함정들을 강행돌파하기도 어려워 보이고.","JPN":"ふーん。確かに、悪くないやり方だね。この罠を強行突破するのも難しそうだし。","ENG":"Hmm... That's not such a bad idea. And trying to brute force it through all these traps seems like a lot of work.","TWN":"嗯嗯，這個方法確實不錯，再說好像也無法強行突破這些陷阱。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잘됐네. 그럼 팀으로 참가하자.","JPN":"よかった。じゃあ、チームで参加しよう。","ENG":"Okay. Then let's enter as a team.","TWN":"好欸，那我們就組隊參加吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"……응? 팀?","JPN":"……え？　チーム？","ENG":"...Huh? A team?","TWN":"……蛤？組隊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아.","JPN":"あ。 ","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"규칙을 검색해 보니까 이기기만 하면 돼.","JPN":"ルールを検索してみたけど、勝てばいいみたい。","ENG":"I looked up the rules and it just says we have to win.","TWN":"我有查過規則，好像只要能贏就好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"한 명이어야 한다는 규칙은 확실히 없네. 이미 팀으로 덤빈 사람들도 꽤 있는 모양인데?","JPN":"一人じゃないとダメってルールはないね。チームで挑戦した人たちも結構いるみたいだ。","ENG":"There's nothing about it having to be just one person. Also, there seems to be a lot of people entering as teams already.","TWN":"沒有明文規定只能一個人參加，應該有很多人都是組隊的吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"규, 규칙이 없다 해도 팀으로 덤비라는 의도는 아니지 않았을까……?","JPN":"る、ルールはなくてもチームで挑戦しろという意図ではないんじゃないかな……？","ENG":"B-but just because it doesn't say you can't doesn't mean you should, right...?","TWN":"就…就算沒有規定人數，但主辦單位應該不希望大家組隊參加吧……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리 목적은 차세대 헤이븐이 아니라 함선 그 자체인걸.","JPN":"ワタシたちの目的は次世代ヘイブンじゃなくて、艦船そのものなんだ。","ENG":"Our objective is the ship itself, not becoming the next Haven.","TWN":"我們的目標不是成為下一個天堂，而是艦船本身。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"네 말도 맞긴 해. 그래도 재미라는 건 규칙을 지켜야…….","JPN":"それもそうなんだけど。楽しさっていうのはルールを守らないと……","ENG":"You're right, but... Wouldn't following the rules be more fun...?","TWN":"你說的是沒錯，但是要遵守規則才有運動家精……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"좋았어! 첫 번째는 어디로 갈까?","JPN":"よし！　どこから行く？","ENG":"All right! Where do we head first?","TWN":"OK！那第一關要往哪？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아까 들렀던 라스트 헤이븐이 제일 가까워. 거기서부터 다시 시작하자.","JPN":"さっき寄ったラストヘイブンが一番近いね。そこからやり直そう。","ENG":"Last Haven is the closest. Let's start from there.","TWN":"剛剛路過的最後的天堂是最近的，就從那裡重新開始吧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 나를 따르라~","JPN":"おお、ついてこーい！","ENG":"Ooh! Follow me!","TWN":"哇喔，跟我走～"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"자, 잠깐만! 얘들아! 내 생각이 좀 짧았던 것 같아! 얘들아?!","JPN":"ちょ、ちょっと！　みんな！　やっぱりもうちょっと考えてから……みんな！？","ENG":"W-wait! Girls! I wasn't thinking straight! Girls?","TWN":"先…先等一下！你們聽我說！我剛剛沒想清楚！先等一下啦？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아직도 못 찾았다고?","JPN":"まだ見つからないの？","ENG":"You still haven't found him?","TWN":"還沒找到嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"다들 정신 안 차려? 밥버러지처럼 살려면 여기 있지 말고 지상으로 꺼져!","JPN":"しっかりしなさいよ。食うだけの役立たずならさっさと地上に下りてしまいなさい！","ENG":"FIND HIM, OR ELSE! If you're not going to do your job, then get off this ship and live on the ground!","TWN":"你們是幹什麼吃的？你們是米蟲嗎？要當米蟲的話就給我滾到陸地上！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"진정하시죠, 마담. 백방으로 찾고 있습니다.","JPN":"落ち着いてください、マダム。あらゆる手を尽くして探させています。","ENG":"Madam, please calm down. I'm doing my best to look for him.","TWN":"夫人請先冷靜，大家已經分頭去找。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"최근에 워낙 헤이븐 형님을 따라하는 무리들이 늘어나서 지체되고 있을 뿐입니다.","JPN":"最近ヘイブン兄貴の真似をするやつらが増えたので、遅れているだけです。","ENG":"It's only a minor setback as an increasing number of Mr. Haven's fans started dressing up like him recently.","TWN":"因為最近有許多人都在模仿天堂大哥，才會花比較長的時間。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"시기를 고려하면 함선 안에 계신 건 확실하지 않습니까.","JPN":"時期を考えると艦船内にいらっしゃるのは確かではないですか。","ENG":"But judging by the timeline, we are certain he's still somewhere on the ship.","TWN":"現在這個時候，我想大哥應該在艦船裡。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"확실한 게 문제가 아니라 당장 데려와야 한다고!","JPN":"確かかどうかが問題じゃないのよ。今すぐ連れて来て！","ENG":"That's not the problem... I said, BRING HIM TO ME NOW!","TWN":"你想什麼不重要，重點是我要你們立刻把人帶來！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"곧 검은 평의회 의장님께서 방문하신다니까? 이게 얼마나 중요한 일인지 몰라?!","JPN":"もうすぐ黒の評議会の議長がいらっしゃるのよ？　これがどれほど重要なことなのかわからないの！？","ENG":"The Chairman of the Dark Council will be here soon. Don't you know how important this is?!","TWN":"黑暗評議會的議長就快要來訪，你不知道這件事有多重要嗎？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"평의회에서 우리 입지를 다지려면 이번 기회를 최대한 활용하는 수밖에 없다고!","JPN":"評議会での私たちの立場を固めるためには、今度の機会を最大限活用するしかないわ！","ENG":"We must seize this opportunity to strengthen our position in the Council!","TWN":"我們要是想在評議會立足，就必須好好把握這次機會！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"……최선을 다하겠습니다.","JPN":"……最善を尽くします。","ENG":"...I will do my best.","TWN":"……我們會努力把人帶來的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"피곤해 보이시는데, 잠시 쉬시죠. 그럼.","JPN":"お疲れのようですからしばらくお休みください。それでは。","ENG":"You look exhausted, Madam. Please, rest a little while I go look for him.","TWN":"夫人看起來有點累，就不打擾您休息。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아…… 다 머저리 같은 것들뿐이야.","JPN":"はあ……みんなそろって馬鹿ばかり。","ENG":"*Sigh... * They're all babbling idiots.","TWN":"哀……都是些沒用的東西。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"멍청한 헤이븐님. 노느라 정신 팔려서 뭐가 중요한지도 모르다니.","JPN":"愚かなヘイブン様。遊びに気をとられて何が大事かもわからないなんて。","ENG":"Stupid Haven. I can't believe he's so lost in playing around that he's forgotten what's important.","TWN":"愚蠢的天堂，竟然玩到連事情的輕重緩急都不知道！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"할 수 없지. 의장님을 맞이하는 일은 내가 하는 수밖에.","JPN":"仕方ないわ。議長のお迎えは私がやるしかない。","ENG":"Well, then... I guess I'll just have to greet the Chairman myself.","TWN":"沒辦法，只好由我來親自接待議長。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제 발로 굴러 들어오는 복을 걷어차다니. 멍청하긴.","JPN":"転がり込んだ福を自分の足で蹴とばすなんて。まったく愚かね。","ENG":"Stupid boy... Never any luck for you.","TWN":"竟然將這麼好的機會拱手讓人，真是愚蠢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래. 넌 지금보다 훨씬 더 높이 올라갈 수 있는 여자야, 헤론. 자신감을 가져.","JPN":"そう。あなたは今よりもっと高いところまで登りつめることのできる女だわ、ヘロン。自信を持って。","ENG":"That's right, Heron. You're a woman who can soar much higher than this. Have faith in yourself.","TWN":"沒錯，海倫，你是可以爬得比現在更高的女人，要有信心！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님을 맞이하는 일은 내가 하면 될 것을.","JPN":"議長をお迎えするのは私がやればいいのよ。","ENG":"I will greet the Chairman myself.","TWN":"由我來接待議長沒問題的！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"피곤하긴 한가 보네. 아무도 없는 데서 혼잣말이나 하고.","JPN":"本当に疲れてるみたい。誰もいないところで独り言なんて言って。","ENG":"I guess I'm exhausted. Talking to myself like this.","TWN":"看來我確實是有點累，竟然在這邊自言自語。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이게 다 그 악몽 때문이야. 수면 부족 때문에 뭐 하나 제대로 풀리는 일이 없어.","JPN":"全部あの悪夢のせいだわ。睡眠不足で何一つうまくいかない。","ENG":"It's all because of that nightmare. My lack of sleep is ruining everything for me.","TWN":"都是惡夢害的，睡眠不足搞得我沒一件事是順利的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아니, 이럴 때가 아니지. 의장님과 독대하려면 단장을 해야 하잖아?","JPN":"いいえ、こうしてる場合じゃないわ。議長とお会いするためには身なりを整えないと。","ENG":"No, now is not the time to think about that. I should get ready to greet the Chairman.","TWN":"不行，現在不是睡覺的時候，要單獨見議長，不梳妝打扮一下怎麼行？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴우. 이 다크 서클 짙은 것 좀 봐.","JPN":"ふう。この濃いクマ、どうしようかしら。","ENG":"*Sigh* Look at those bags under my eyes.","TWN":"哀，看看我這熊貓眼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아, 아니지. 오히려 평의회를 위해 몸 바쳐 일하고 있다는 걸 알아 주시려나?","JPN":"いいえ、待って。むしろ評議会のために身を削って仕事をしていると思ってくれるかも。","ENG":"No, wait. Maybe those could show how hard I'm working for the Council?","TWN":"不，議長會不會反而認為我是沒日沒夜在為評議會做事？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럼 다크 서클은 내버려 두고…….","JPN":"じゃあ、ダークサークルはそのままに……","ENG":"Then let's leave them be and...","TWN":"那黑眼圈就先不遮……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};